package main

import "fmt"

func factorial(n int) int {
    if n <= 1 {
        return 1
    }
    return n * factorial(n-1)
}

func reverse(s string) string {
    if len(s) <= 1 {
        return s
    }
    return reverse(s[1:]) + string(s[0])
}

func main() {
    fmt.Println("factorial(6):", factorial(6))
    fmt.Println("reverse('hello'):", reverse("hello"))
}
